import { isNil } from 'lodash-es';

import {
  _OverlayTooltip as OverlayTooltip,
  _OverlayTooltipData as Data,
  _useDefaultConfig as useDefaultConfig,
  _useDefaultLabels as useDefaultLabels,
  type SeriesActionsTemplate,
} from '@dynatrace/strato-components/charts';
import Colors from '@dynatrace/strato-design-tokens/colors';
import { LocationMarkerFilledIcon } from '@dynatrace/strato-icons';

import { useTruncationMode } from '../../hooks/use-truncation-mode.js';
import type { Location } from '../../types/location.js';
import type {
  BubbleLayerTooltipData,
  ChoroplethLayerTooltipData,
  ConnectionLayerTooltipData,
  DotLayerTooltipData,
  LayerTooltipData,
} from '../../types/tooltip.js';
import { isConnection, isRegion } from '../../utils/tooltip-type-guards.js';

const isChoroplethTooltip = (
  props: DefaultTooltipProps,
): props is {
  closestPoint: ChoroplethLayerTooltipData;
  seriesActions?: (
    data: Location | ChoroplethLayerTooltipData,
  ) => SeriesActionsTemplate;
} => isRegion(props.closestPoint);
const isConnectionTooltip = (
  props: DefaultTooltipProps,
): props is {
  closestPoint: ConnectionLayerTooltipData;
} => isConnection(props.closestPoint);
const isBubbleTooltip = (
  props: DefaultTooltipProps,
): props is {
  closestPoint: BubbleLayerTooltipData;
  layerData: BubbleLayerTooltipData[];
} => !isNil(props.layerData);

const isDotTooltip = (
  props: DefaultTooltipProps,
): props is {
  closestPoint: DotLayerTooltipData;
} => true; // if it's not any of the other tooltips, it will be Dot

type SeriesData = Data['series'][number];

interface DefaultTooltipProps {
  closestPoint: LayerTooltipData;
  layerData?: LayerTooltipData[];
  actionsForItem?: (
    item: SeriesData,
  ) => (() => SeriesActionsTemplate) | undefined;
  seriesActions?: (
    data: Location | ChoroplethLayerTooltipData,
  ) => SeriesActionsTemplate;
}

export const DefaultTooltip = (props: DefaultTooltipProps) => {
  const defaultConfig = useDefaultConfig();
  const getLabel = useDefaultLabels();
  const truncationMode = useTruncationMode();
  let locations: Location[] = [];

  if (isChoroplethTooltip(props)) {
    const { closestPoint, seriesActions } = props;
    return (
      <OverlayTooltip truncation={truncationMode}>
        <OverlayTooltip.SeriesHeader valueLabel="" />
        <OverlayTooltip.SeriesItem
          color={closestPoint.color}
          name={closestPoint.name}
          value={closestPoint.data.value?.toString() ?? ''}
          actions={
            seriesActions ? () => seriesActions(closestPoint) : undefined
          }
        />
      </OverlayTooltip>
    );
  } else if (isConnectionTooltip(props)) {
    locations = props.closestPoint.data.path;
  } else if (isBubbleTooltip(props)) {
    const { closestPoint, layerData } = props;
    locations =
      layerData === undefined || layerData === null || layerData.length === 0
        ? [closestPoint.data]
        : layerData.map((point) => point.data);
  } else if (isDotTooltip(props)) {
    locations = [props.closestPoint.data];
  }

  const seriesLabel = getLabel?.('seriesLabel') ?? '';
  const variant = defaultConfig?.sharedVariant ? 'shared' : 'single';

  const seriesData = locations.map((location) => ({
    name: `${location.latitude}, ${location.longitude}`,
    value: '',
  }));

  const getActionsForItem = (
    current: SeriesData,
  ): (() => SeriesActionsTemplate) | undefined => {
    if (props.actionsForItem) {
      return props.actionsForItem(current);
    }
    const { seriesActions: actions } = props;
    if (!actions || !locations.length) {
      return undefined;
    }
    const location = locations.find(
      (l) => `${l.latitude}, ${l.longitude}` === current.name,
    );
    return location ? () => actions(location) : undefined;
  };

  return (
    <OverlayTooltip truncation={truncationMode}>
      <OverlayTooltip.Header header1={seriesLabel} />
      <OverlayTooltip.SeriesHeader disabled />
      <OverlayTooltip.Series
        activeItem={0}
        data={seriesData}
        variant={variant}
        seriesItemTemplate={(current) => (
          <OverlayTooltip.SeriesItem
            {...current}
            iconStyle="large"
            actions={getActionsForItem(current as SeriesData)}
            icon={
              <LocationMarkerFilledIcon
                style={{
                  fill: Colors.Text.Neutral.Default,
                }}
              />
            }
          />
        )}
      />
    </OverlayTooltip>
  );
};

DefaultTooltip['displayName'] = 'DefaultTooltip';
